    def findMaximumXOR(self, nums: list[int]) -> int:
        max_mask = 0
        for num in nums:
            max_mask |= num
        max_mask = max_mask.bit_length() - 1
        prefix_tree = {}
        ans = 0
        for i in range(max_mask, -1, -1):
            prefix_tree = {}
            for num in nums:
                if (num >> i) & 1:
                    prefix_tree.setdefault((num >> (i + 1)) << (i + 1), []).append(num)
                else:
                    prefix_tree.setdefault(((num >> (i + 1)) ^ 1) << (i + 1), []).append(num)
            cur = 0
            for j in range(max_mask, i, -1):
                cur |= 1 << j
                if (cur >> (i + 1)) ^ 1 in prefix_tree:
                    if prefix_tree[(cur >> (i + 1)) ^ 1]:
                        ans = cur
                        break
            if ans:
                break
        return ans

