#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int findMaximumXOR(vector<int>& nums) {
        int max_mask = 0;
        for (int num : nums) {
            max_mask |= num;
        }
        int max_bit = 31 - __builtin_clz(max_mask);
        int ans = 0;
        for (int i = max_bit; i >= 0; --i) {
            unordered_map<int, vector<int>> prefix_tree;
            for (int num : nums) {
                if (num & (1 << i)) {
                    prefix_tree[num >> (i + 1)].push_back(num);
                } else {
                    prefix_tree[(num >> (i + 1)) ^ 1].push_back(num);
                }
            }
            int cur = 0;
            for (int j = max_bit; j > i; --j) {
                cur |= 1 << j;
                if (prefix_tree.find((cur >> (i + 1)) ^ 1) != prefix_tree.end() && !prefix_tree[(cur >> (i + 1)) ^ 1].empty()) {
                    ans = cur;
                    break;
                }
            }
            if (ans) {
                break;
            }
        }
        return ans;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    Solution sol;
    int ans = sol.findMaximumXOR(nums);
    cout << ans << '\n';
    return 0;
}
